function parseStreamedJSON(rawStreamText) {
  const lines = rawStreamText.split('\n');
  let accumulatedString = '';

  for (const line of lines) {
    const trimmedLine = line.trim();

    // Process only lines that start with "data: " (Server-Sent Events)
    if (trimmedLine.startsWith('data: ')) {
      const jsonChunk = trimmedLine.slice(6); 

      try {
        const parsedChunk = JSON.parse(jsonChunk);
        // Safely extract the text fragment using optional chaining
        const textFragment = parsedChunk.candidates?.[0]?.content?.parts?.[0]?.text;

        if (textFragment) {
          accumulatedString += textFragment;
        }
      } catch (error) {
        console.warn("Failed to parse an individual chunk:", error);
      }
    }
  }

  // Parse the fully assembled string into the final JSON object
  try {
    const finalData = JSON.parse(accumulatedString);
    return {
        parsedObject: finalData,
        // Construct the parts array exactly as required by the Gemini API contents schema
        modelParts: [{ text: accumulatedString }] 
    };
  } catch (error) {
    console.error("Failed to parse the final assembled string. The combined JSON might be invalid.", error);
    return {
        parsedObject: null,
        // Return the raw accumulated string even on failure to assist with pipeline debugging
        modelParts: [{ text: accumulatedString }] 
    };
  }
}

// Loop over input items and append both the parsed data and the model parts
for (const item of $input.all()) {
  let result = parseStreamedJSON(item.json.data);

  // The structured data for PocketBase persistence
  item.json.parsedContentObject = result.parsedObject;

  // The conversational history payload for the next Gemini HTTP request
  item.json.modelParts = result.modelParts; 
}

return $input.all();
